+};
+
+type BindingState = {
+  ready: boolean;
+  disabled: boolean;
+  configDirty: boolean;
+  configLoading: boolean;
+  configSaving: boolean;
+  defaultBinding?: string | null;
+  agents: BindingAgent[];
+  nodes: BindingNode[];
+  onBindDefault: (nodeId: string | null) => void;
+  onBindAgent: (agentIndex: number, nodeId: string | null) => void;
